using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// "Câmara aquática" (Tarefa #14): feedback visual de estar dentro/submerso em
/// água através de um overlay de cor num Canvas (Screen Space - Overlay), sem
/// depender de post-processing.
///
/// Montagem no Editor:
/// - Criar um Canvas (Screen Space - Overlay) com uma Image full-screen
///   (esticada aos 4 cantos), cor inicial transparente.
/// - Colocar este script num GameObject qualquer da cena e ligar
///   "overlayImage" a essa Image e "playerWaterDetector" ao WaterDetector do
///   player (auto-detectado por FindObjectOfType se ficar vazio).
/// </summary>
public class WaterCameraEffect : MonoBehaviour
{
    [SerializeField] private WaterDetector playerWaterDetector;
    [SerializeField] private Image overlayImage;

    [Header("Cores")]
    [Tooltip("Overlay enquanto à superfície da água (cabeça fora).")]
    public Color surfaceColor = new Color(0.2f, 0.55f, 0.85f, 0.10f);

    [Tooltip("Overlay enquanto submerso (cabeça dentro de água).")]
    public Color submergedColor = new Color(0.1f, 0.35f, 0.7f, 0.32f);

    [Tooltip("Overlay fora de água (sem efeito).")]
    public Color outOfWaterColor = new Color(0f, 0f, 0f, 0f);

    [Tooltip("Velocidade de transição entre cores (por segundo).")]
    public float lerpSpeed = 4f;

    private void Awake()
    {
        if (playerWaterDetector == null)
            playerWaterDetector = FindObjectOfType<WaterDetector>();
    }

    private void Update()
    {
        if (overlayImage == null || playerWaterDetector == null) return;

        Color target = outOfWaterColor;
        if (playerWaterDetector.IsSubmerged) target = submergedColor;
        else if (playerWaterDetector.IsInWater) target = surfaceColor;

        overlayImage.color = Color.Lerp(overlayImage.color, target, lerpSpeed * Time.unscaledDeltaTime);
    }
}
